final:
module RefModule(
    input wire status,
    input wire reset,
    input wire clk,  
    input wire [31:0] d_en, 
    output wire [31:0] data    
);reg [31:0]d_sal; 

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset  or posedge dbg_halt)
    if (reset==1'b1)
           d_sal=0;
    else
    d_sal <= d_en;

assign data=d_sal;
endmodule
